diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 9a16ca96db76..9061b6a92ffd 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -962,6 +962,28 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
       }
     }
   }
+  // add(zext nneg (add nsw X, C1)), C2 --> add (sext X), C1 + C2
+  BinaryOperator *InnerAdd;
+  if (match(Op0, m_ZExt(m_BinOp(InnerAdd))) &&
+      cast<ZExtInst>(Op0)->hasNonNeg()) {
+    Value *X;
+    const APInt *C1;
+    if (match(InnerAdd, m_NSWAdd(m_Value(X), m_APInt(C1))) ||
+        match(InnerAdd, m_NSWAdd(m_APInt(C1), m_Value(X)))) {
+      APInt C1Ext = C1->sext(Ty->getScalarSizeInBits());
+      APInt NewC = C1Ext + *C;
+      if (NewC.isZero())
+        return CastInst::Create(Instruction::SExt, X, Ty);
+      Value *Sext = CastInst::Create(Instruction::SExt, X, Ty);
+      Builder.Insert(Sext);
+      BinaryOperator *NewAdd = BinaryOperator::CreateAdd(Sext, ConstantInt::get(Ty, NewC));
+      // Preserve NSW if both original adds have NSW.
+      if (Add.hasNoSignedWrap() && InnerAdd->hasNoSignedWrap())
+        NewAdd->setHasNoSignedWrap(true);
+      // TODO: NUW?
+      return NewAdd;
+    }
+  }

   if (C->isOne() && Op0->hasOneUse()) {
     // add (sext i1 X), 1 --> zext (not X)

